import java.util.*;class DoublyLibrary{static class N{String t,a;int id;boolean av;N next,prev;N(String t,String a,int id,boolean av){this.t=t;this.a=a;this.id=id;this.av=av;}}static N head;static void add(String t,String a,int id,boolean av){N n=new N(t,a,id,av);if(head==null)head=n;else{head.prev=n;n.next=head;head=n;}}static void display(){N c=head;while(c!=null){System.out.println(c.t+" "+c.a+" "+c.id+" "+c.av);c=c.next;}}public static void main(String[] a){add("B1","A1",1,true);add("B2","A2",2,false);display();}}